SELECT polls.poll_id, polls.middate_time, polls.pollster_id, polls.clinton, polls.trump, polls.margin
FROM polls
INNER JOIN pollsters ON polls.pollster_id = pollsters.pollster_id;

SELECT p.poll_id, pt.tag_name
FROM polls p
JOIN poll_tags pt ON p.poll_id = pt.poll_id;

SELECT * 
FROM polls 
ORDER BY middate_time;

SELECT poll_id, middate_time,
       NTILE(4) OVER (ORDER BY margin) AS Quartile
FROM polls;

SELECT AVG(margin_of_error)
FROM polls
WHERE poll_type_id = (SELECT poll_type_id FROM poll_types WHERE poll_type_name = 'National');

SELECT poll_id, AVG(rating) AS average_rating, MIN(rating) AS min_rating, MAX(rating) AS max_rating
FROM poll_ratings
GROUP BY poll_id;

SELECT poll_id, middate_time
FROM polls
WHERE pollster_id = 1 AND poll_type_id = 1;
